tasks.before:
echo '
export COOKIE_DOMAIN=gitpod.io
export HOME_LOCATION=$(gp url 8000)
export API_LOCATION=$(gp url 3000)
export CYPRESS_BASE_URL=$(gp url 8000)
export REACT_APP_CHALLENGE_EDITOR_API_LOCATION=$(gp url 3200)
export CHALLENGE_EDITOR_CLIENT_LOCATION=$(gp url 3300)
' >> ~/.bashrc;
exit;

tasks.command:
clear
echo "Once the docs server is running, go to the following URL to view the docs:

$(gp url 8080)"

if ! [[ $(git config --global --get user.email) =~ .*@users.noreply.github.com ]]
then git config --global --remove-section user; echo;
echo "Git user details weren't using noreply email and have been removed"; echo; fi

gp ports await 5432
sleep 3
export ENDPOINT=$(gp url 3001)
export ADMIN_ENDPOINT=$(gp url 3002)
pnpm cli db seed
pnpm start:dev

